var suggestions=document.getElementById('suggestions'),search=document.getElementById('search');search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(c){const d=suggestions.classList.contains('d-none');if(d)return;const a=[...suggestions.querySelectorAll('a')];if(a.length===0)return;const b=a.indexOf(document.activeElement);if(c.key==="ArrowUp"){c.preventDefault();const d=b>0?b-1:0;a[d].focus()}else if(c.key==="ArrowDown"){c.preventDefault();const d=b+1<a.length?b+1:b;a[d].focus()}}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description","content"]}});a.add({id:0,href:"/docs/cheat-sheet/ansible/",title:"ansible",description:"ansible commands",content:"Doc # Doc\nPlaybook Example: # --- - hosts: all become: yes tasks: # Docker Compose - name: Check Docker compose bin file presence stat: path=/usr/local/bin/docker-compose register: dockercompose - name: Install docker compose shell: curl -L https://github.com/docker/compose/releases/download/1.5.2/docker-compose-`uname -s`-`uname -m` \u0026gt; /usr/local/bin/docker-compose when: dockercompose.stat.exists == false - name: Apply executable permission file: path=/usr/local/bin/docker-compose mode=\u0026quot;u+x,g+x\u0026quot; - name: docker port ouverture =\u0026gt; kitematic conf command: echo DOCKER_OPTS=\u0026quot;-H unix:///var/run/docker.sock -H tcp://0.0.0.0:2375\u0026quot; \u0026gt; /etc/default/docker # command: service docker restart - name: Enable i386 architecture command: dpkg --add-architecture i386 - name: Ensure apt cache is up to date apt: upgrade apt: update_cache=yes - name: Install unzip apt: name: unzip state: installed update_cache: true - name: Install Open JDK apt: name: openjdk-8-jdk command: chmod -R +x $JAVA_HOME  "}).add({id:1,href:"/docs/cheat-sheet/docker/",title:"docker",description:"docker commands",content:"The everything # https://github.com/wsargent/docker-cheat-sheet\ndocker + vscode # https://www.docker.com/blog/video-docker-build-working-with-docker-and-vscode/\nGeneral Commands # #container docker container ls docker container prune #images docker image ls -a docker image prune -a #sys docker system info docker system prune #network docker network ls  Dockerfile example # version: '2.1' services: users-db: container_name: users-db build: context: ../usersTDDC/project/db # context: https://github.com/upcreid/usersTDDC.git#master:project/db ports: - 5435:5432 # expose ports - HOST:CONTAINER environment: - POSTGRES_USER=postgres - POSTGRES_PASSWORD=postgres healthcheck: test: exit 0 users-service: container_name: users-service build: context: ../usersTDDC dockerfile: Dockerfile-local # build: https://github.com/upcreid/usersTDDC.git volumes: - '../usersTDDC:/usr/src/app' # If working on docker machine on linux dont do this ! only win or osx ports: - \u0026quot;5001:5000\u0026quot; environment: - APP_SETTINGS=project.config.DevelopmentConfig - DATABASE_URL=postgres://postgres:postgres@users-db:5432/users_dev - DATABASE_TEST_URL=postgres://postgres:postgres@users-db:5432/users_test - SECRET_KEY=my_precious depends_on: users-db: condition: service_healthy links: - users-db nginx: container_name: nginx build: ./nginx/ restart: always ports: - 80:80 depends_on: users-service: condition: service_started web-service: condition: service_started links: - users-service - web-service web-service: container_name: web-service build: # context: https://github.com/upcreid/clientTDDC.git context: ../clientTDDC dockerfile: Dockerfile-local environment: - NODE_ENV=development - REACT_APP_USERS_SERVICE_URL=http://localhost volumes: - '../clientTDDC:/usr/src/app' - '/usr/src/app/node_modules' ports: - '9000:9000' # expose ports - HOST:CONTAINER depends_on: users-service: condition: service_started links: - users-service swagger: container_name: swagger build: context: ../swaggerTDDC ports: - '8080:8080' # expose ports - HOST:CONTAINER environment: - API_URL=https://raw.githubusercontent.com/upcreid/swaggerTDDC/master/swagger.json depends_on: users-service: condition: service_started  It contains: # .tg {border-collapse:collapse;border-spacing:0;} .tg td .tg thword-break:normal;} .tg .tg-jruv{font-size:13px;vertical-align:top} .tg .tg-b3rt{font-weight:bold;font-size:15px;vertical-align:top}   service name   db postgres users-db   front react web-service   back python users-service   nginx nginx   swagger swagger   "}).add({id:2,href:"/docs/cheat-sheet/git/",title:"git",description:"git commands",content:"Git en 2-2 from buzut # https://buzut.fr/git-en-2-2/\nGit immersion # http://gitimmersion.com//\nGit explorer # https://github.com/summitech/gitexplorer\n"}).add({id:3,href:"/docs/cheat-sheet/shell/",title:"shell",description:"shell commands",content:" grep + find, sed awk  The bible\nfind # The Geek Stuff – 15 Find Commands\nThe Geek Stuff – 15 More Find Commands\nIBM – Advanced Find Techniques\ngrep # The Geek Stuff – 15 Grep Commands\nsed # John Cook – Learn a little sed\nThe Geek Stuff – Sed Tips and Tricks\nBruce Barnett – Sed Tutorial and Introduction\nFamous sed one-liners explained\nawk # Greg Grothaus – Why you should learn just a little awk\nThe Geek Stuff – 8 Powerful Awk Built-in Variables\nSteve’s awk academy\nBruce Barnett – Awk Tutorial and Introduction\nSimple awk tutorial\nFamous awk one-liners explained\nMotivation/Philospophy: # John Cook on Greg Grothaus on awk\nGeneral command-line introduction: # The Geek Stuff – 50 Linux Commands\n cut vmstat uptime  "}).add({id:4,href:"/docs/cheat-sheet/sql/",title:"sql",description:"sql commands",content:"select * from table where u \u0026gt; 1;  mcd designer: # http://ondras.zarovi.cz/sql/demo/\nsqlZoo, if you loose your mind !!!: # http://sqlzoo.net/wiki/SQL_Tutorial\n"}).add({id:5,href:"/docs/starcraft/params/",title:"starcraft2 params",description:"starcraft2 params",content:"sc2 params thanks to: www.TerranCraft.com\n Graphics Graphics and Textures: Sound Control mouse Gameplay Hybrid Settings  Graphics #  Display mode: Fullscreen Resolution: 1920 x 1080 Vertical syn: Disable Refresh rate: Default Reduced violence: Enable  Graphics and Textures: #  High for models Medium for shaders, shadows and effects Low for everything else  Sound #  Music: Disable Ambient sound: Disable Move sound: 100% Sound quality: Low Voices sound: Enable Error sound: Enable  Control # Set your window mouse setting to the following before you do the in game changes below.\nmouse #    Mouse sensitivity: Enable Mouse sensitivity: 52% Mouse wheel zoom: Enable Reduce mouse lag: Disable Windows key: Disable Mouse scroll: Enable Invert drag scroll: Disable Smart camera pan: Disable  Gameplay #  Alert: Disable Game timer: Enable Build grid: Enable Work status: Enable Current order indicator: Enable Select all larva: Disable Enemy unit selection: Enable Experience points: Enable Show unit life bar: Always or damaged Control group: Unclickable or hidden Flyer helper: Always  Hybrid Settings # Hybrid Settings\n"}).add({id:6,href:"/docs/cheat-sheet/tmux/",title:"tmux",description:"tmux commands",content:"tmux shortcuts \u0026amp; cheatsheet # start new:\ntmux  start new with session name:\ntmux new -s myname  attach:\ntmux a # (or at, or attach)  attach to named:\ntmux a -t myname  list sessions:\ntmux ls  kill session:\ntmux kill-session -t myname  Kill all the tmux sessions:\ntmux ls | grep : | cut -d. -f1 | awk '{print substr($1, 0, length($1)-1)}' | xargs kill  In tmux, hit the prefix ctrl+b (my modified prefix is ctrl+a) and then:\nList all shortcuts # to see all the shortcuts keys in tmux simply use the bind-key ? in my case that would be CTRL-B ?\nSessions # :new\u0026lt;CR\u0026gt; new session s list sessions $ name session  Windows (tabs) # c create window w list windows n next window p previous window f find window , name window \u0026amp; kill window  Panes (splits) # % vertical split \u0026quot; horizontal split o swap panes q show pane numbers x kill pane + break pane into window (e.g. to select text by mouse to copy) - restore pane from window ⍽ space - toggle between layouts \u0026lt;prefix\u0026gt; q (Show pane numbers, when the numbers show up type the key to goto that pane) \u0026lt;prefix\u0026gt; { (Move the current pane left) \u0026lt;prefix\u0026gt; } (Move the current pane right) \u0026lt;prefix\u0026gt; z toggle pane zoom  Sync Panes # You can do this by switching to the appropriate window, typing your Tmux prefix (commonly Ctrl-B or Ctrl-A) and then a colon to bring up a Tmux command line, and typing:\n:setw synchronize-panes  You can optionally add on or off to specify which state you want; otherwise the option is simply toggled. This option is specific to one window, so it won’t change the way your other sessions or windows operate. When you’re done, toggle it off again by repeating the command. tip source\nResizing Panes # You can also resize panes if you don’t like the layout defaults. I personally rarely need to do this, though it’s handy to know how. Here is the basic syntax to resize panes:\nPREFIX : resize-pane -D (Resizes the current pane down) PREFIX : resize-pane -U (Resizes the current pane upward) PREFIX : resize-pane -L (Resizes the current pane left) PREFIX : resize-pane -R (Resizes the current pane right) PREFIX : resize-pane -D 20 (Resizes the current pane down by 20 cells) PREFIX : resize-pane -U 20 (Resizes the current pane upward by 20 cells) PREFIX : resize-pane -L 20 (Resizes the current pane left by 20 cells) PREFIX : resize-pane -R 20 (Resizes the current pane right by 20 cells) PREFIX : resize-pane -t 2 20 (Resizes the pane with the id of 2 down by 20 cells) PREFIX : resize-pane -t -L 20 (Resizes the pane with the id of 2 left by 20 cells)  Copy mode: # Pressing PREFIX [ places us in Copy mode. We can then use our movement keys to move our cursor around the screen. By default, the arrow keys work. we set our configuration file to use Vim keys for moving between windows and resizing panes so we wouldn’t have to take our hands off the home row. tmux has a vi mode for working with the buffer as well. To enable it, add this line to .tmux.conf:\nsetw -g mode-keys vi  With this option set, we can use h, j, k, and l to move around our buffer.\nTo get out of Copy mode, we just press the ENTER key. Moving around one character at a time isn’t very efficient. Since we enabled vi mode, we can also use some other visible shortcuts to move around the buffer.\nFor example, we can use \u0026ldquo;w\u0026rdquo; to jump to the next word and \u0026ldquo;b\u0026rdquo; to jump back one word. And we can use \u0026ldquo;f\u0026rdquo;, followed by any character, to jump to that character on the same line, and \u0026ldquo;F\u0026rdquo; to jump backwards on the line.\n Function vi emacs Back to indentation ^ M-m Clear selection Escape C-g Copy selection Enter M-w Cursor down j Down Cursor left h Left Cursor right l Right Cursor to bottom line L Cursor to middle line M M-r Cursor to top line H M-R Cursor up k Up Delete entire line d C-u Delete to end of line D C-k End of line $ C-e Goto line : g Half page down C-d M-Down Half page up C-u M-Up Next page C-f Page down Next word w M-f Paste buffer p C-y Previous page C-b Page up Previous word b M-b Quit mode q Escape Scroll down C-Down or J C-Down Scroll up C-Up or K C-Up Search again n n Search backward ? C-r Search forward / C-s Start of line 0 C-a Start selection Space C-Space Transpose chars C-t  Misc # d detach t big clock ? list shortcuts : prompt  Configurations Options: # # Mouse support - set to on if you want to use the mouse * setw -g mode-mouse off * set -g mouse-select-pane off * set -g mouse-resize-pane off * set -g mouse-select-window off # Set the default terminal mode to 256color mode set -g default-terminal \u0026quot;screen-256color\u0026quot; # enable activity alerts setw -g monitor-activity on set -g visual-activity on # Center the window list set -g status-justify centre # Maximize and restore a pane unbind Up bind Up new-window -d -n tmp \\; swap-pane -s tmp.1 \\; select-window -t tmp unbind Down bind Down last-window \\; swap-pane -s tmp.1 \\; kill-window -t tmp  "}).add({id:7,href:"/docs/cheat-sheet/vagrant/",title:"vagrant",description:"vagrant commands",content:"Exemple de conf Vagrantfile: # # -*- mode: ruby -*- # vi: set ft=ruby : # All Vagrant configuration is done below. The \u0026quot;2\u0026quot; in Vagrant.configure # configures the configuration version (we support older styles for # backwards compatibility). Please don't change it unless you know what # you're doing. Vagrant.configure(\u0026quot;2\u0026quot;) do |config| # The most common configuration options are documented and commented below. # For a complete reference, please see the online documentation at # https://docs.vagrantup.com. # Every Vagrant development environment requires a box. You can search for # boxes at https://atlas.hashicorp.com/search. config.vm.box = \u0026quot;ubuntu/xenial64\u0026quot; # Disable automatic box update checking. If you disable this, then # boxes will only be checked for updates when the user runs # `vagrant box outdated`. This is not recommended. config.vm.box_check_update = false # fsnotify config.vm.synced_folder \u0026quot;.\u0026quot;, \u0026quot;/vagrant\u0026quot;, fsnotify: true config.vm.provider \u0026quot;virtualbox\u0026quot; do |vb| vb.name = \u0026quot;default\u0026quot; # vb.gui = true vb.cpus = 2 vb.memory = \u0026quot;5120\u0026quot; end # Port Main Application config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 80, host: 80 # Port docker Engine config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 2375, host: 2375 # Port Mongo config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 27017, host: 27017 # Ionic # Ionic serve config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 8100, host: 8100 # Ionic livereload config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 35729, host: 35729 config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 53703, host: 53703 # Port NodeJS config.vm.network \u0026quot;forwarded_port\u0026quot;, guest: 8400, host: 8400 # Vagrant provision # Docker container config.vm.provision \u0026quot;docker\u0026quot; do |docker| docker.pull_images 'mongo' docker.pull_images 'node' end config.vm.provision \u0026quot;shell\u0026quot;, path: \u0026quot;vagrant-provision/setup.sh\u0026quot; end  "}).add({id:8,href:"/docs/cheat-sheet/vscode/",title:"vscode",description:"vscode commands",content:"Used Extensions #  Dracula Python Prettier Material Icon Theme Go Path Intelisense Bracket Pair Colorized Vetur EditorConfig Indent Rainbow Polacode Settings Sync  Go # ctrl+shift+p      "}).add({id:9,href:"/docs/cheat-sheet/",title:"Cheat Sheet",description:"Cheat Sheet.",content:""}).add({id:10,href:"/docs/",title:"Docs",description:"Docs Doks.",content:""}).add({id:11,href:"/docs/starcraft/",title:"Starcraft",description:'Starcraft."',content:""}),search.addEventListener('input',b,!0);function b(){var b,e;const d=5;b=this.value,e=a.search(b,{limit:d,enrich:!0});const c=new Map;for(const a of e.flatMap(a=>a.result)){if(c.has(a.doc.href))continue;c.set(a.doc.href,a.doc)}if(suggestions.innerHTML="",suggestions.classList.remove('d-none'),c.size===0&&b){const a=document.createElement('div');a.innerHTML=`No results for "<strong>${b}</strong>"`,a.classList.add("suggestion__no-results"),suggestions.appendChild(a);return}for(const[h,g]of c){const b=document.createElement('div');suggestions.appendChild(b);const a=document.createElement('a');a.href=h,b.appendChild(a);const e=document.createElement('span');e.textContent=g.title,e.classList.add("suggestion__title"),a.appendChild(e);const f=document.createElement('span');if(f.textContent=g.description,f.classList.add("suggestion__description"),a.appendChild(f),suggestions.appendChild(b),suggestions.childElementCount==d)break}}})()